mapper.select:
select o.*, u.name as operatorName from [order] o left join [user] u on o.operator_id = u.id


        and u.name like concat('%', #{operatorName}, '%')


        and o.order_sn like concat('%', #{orderSn}, '%')


        and o.create_time >= #{beginTime}


        and o.create_time <= #{endTime}
